'use strict';

var fs = require('node:fs');
var path = require('node:path');
var constants = require('../constants.js');

/* eslint-disable security/detect-non-literal-fs-filename */
function runCLI() {
    const cmd = process.argv[2];
    const srcDir = process.argv[3];
    if (!srcDir || cmd !== 'add-translations') {
        process.exit(0);
        return;
    }
    const translationsListDir = path.resolve(process.env.INIT_CWD, constants.COMMON_DIR);
    const translationsListPath = path.join(translationsListDir, constants.LIB_TRANSLATIONS_FILE);
    if (!fs.existsSync(translationsListDir)) {
        fs.mkdirSync(translationsListDir, { recursive: true });
    }
    const newLibTranslationsPath = path.resolve(srcDir);
    const libs = new Set(fs.existsSync(translationsListPath)
        ? fs.readFileSync(translationsListPath, 'utf-8').split('\n')
        : []);
    libs.add(newLibTranslationsPath);
    fs.writeFileSync(translationsListPath, Array.from(libs).join('\n'), 'utf-8');
}

exports.runCLI = runCLI;
